/* The box model has four layers (inside out):
   content → padding → border → margin */

.card {
  /* Content area */
  width: 300px;
  height: 200px;

  /* Padding: space between content and border */
  padding: 20px;

  /* Border: line around the padding */
  border: 2px solid #333;

  /* Margin: space between this box and other boxes */
  margin: 16px;
}

/* IMPORTANT: by default, width = content only.
   With box-sizing: border-box, width includes padding and border.
   This is almost always what you want. */

*, *::before, *::after {
  box-sizing: border-box; /* Put this in every project */
}

/* With border-box:
   Total width = width (includes padding + border)
   .card is exactly 300px wide, not 300 + 40 + 4 = 344px */

/* Without border-box (content-box default):
   Total width = width + padding-left + padding-right + border-left + border-right
   .card is 300 + 20 + 20 + 2 + 2 = 344px wide */
